function solve(nums: number[]): boolean {
    const n = nums.length;
    for (let p = 1; p < n - 1; p++) {
        for (let q = p + 1; q < n - 1; q++) {
            let isValid = true;
            // Check first part: 0...p strictly increasing
            for (let i = 0; i < p; i++) {
                if (nums[i] >= nums[i + 1]) {
                    isValid = false;
                    break;
